import{_ as a,o as t,c as o,ae as s}from"./chunks/framework.B6gjLfeO.js";const k=JSON.parse('{"title":"Postbacks Overview","description":"","frontmatter":{"title":"Postbacks Overview","slug":"postbacks"},"headers":[],"relativePath":"marketer-hub/postbacks.md","filePath":"marketer-hub/postbacks.md"}'),i={name:"marketer-hub/postbacks.md"};function r(n,e,c,l,h,p){return t(),o("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A postback, with respect to Branch, is quite simply a signal sent from Branch to a specific non-self-attributing ad network (Non-SAN) to notify them of a conversion that happens on the mobile app. Postbacks are helpful for informing marketing teams how well certain campaigns are performing while relaying information to the Non-SAN for them to be able to optimize campaigns.</p><div class="tip custom-block"><p class="custom-block-title">Postbacks vs. Webhooks</p><p>Both the terms <code>Postbacks</code> and <code>Webhooks</code> are used to refer to the same process of sending data to other systems. In Branch’s case, we use the term <code>postback</code> when referring to the Ads product and <code>webhook</code> when referring to the Data Feeds product; though the functionality is the exact same.</p></div><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>Branch Tracking Links and Impression Links are placed in ad campaigns for Non-SANs.</p><ul><li>Tracking Links and Impression Links contain postback macros on it dynamically filled by the ad network.</li></ul></li><li><p>When campaigns are launched, the user sees an app install ad for an app.</p></li><li><p>User downloads and installs the app by clicking the ad and being routed to the app store.</p></li><li><p>When the user opens the app for the first time, the Branch SDK initializes and tracks events performed by the user.</p></li><li><p>Conversions/events are sent through Branch&#39;s attribution systems, and Branch will send a postback to the ad network that drove the conversions.</p></li><li><p>The network claims credit for all postbacks received from Branch.</p></li></ol><h2 id="what-does-it-look-like" tabindex="-1">What does it look like? <a class="header-anchor" href="#what-does-it-look-like" aria-label="Permalink to &quot;What does it look like?&quot;">​</a></h2><p>Postbacks are configured directly on the Branch Dashboard after enabling a specific ad partner. These postbacks can be configured based on your campaign goals and metric specifications.</p>',7)])])}const m=a(i,[["render",r]]);export{k as __pageData,m as default};
